parameters.jsCode:
const items = [];

for (const item of $input.all()) {
  // Buscar la respuesta de la IA en las rutas posibles
  let aiResponse = 
       item.json.message?.content 
    || item.json.content?.[0]?.text 
    || item.json.choices?.[0]?.message?.content
    || item.json.text
    || item.json.output
    || '';

  // Limpiar posibles envoltorios markdown ```json ... ```
  aiResponse = String(aiResponse).replace(/```json|```/g, '').trim();

  try {
    const parsed = JSON.parse(aiResponse);

    items.push({
      json: parsed,
      binary: item.binary  // mantener el PDF adjunto para subir a Drive después
    });
  } catch (e) {
    items.push({
      json: {
        error: 'No se pudo parsear el JSON',
        raw: aiResponse,
        message: e.message
      },
      binary: item.binary
    });
  }
}

return items;

// ═══════════════════════════════════════════
// CONFIGURA TUS IDs DE CARPETA AQUÍ
// Los sacas de la URL: drive.google.com/drive/folders/ESTE_ES_EL_ID
// ═══════════════════════════════════════════
const CARPETAS = {
  proveedor: '1VIpnJvUQvK6JT5tIk4oq_egf_bgEw5dz',
  cliente: '1kUnfu-fs8h74oYl2iA8hjY5YfDhkbbts',
  rectificativa: '1SRjk3Bsk-Pjh0LasSwsODiUouUGTH1yH',
  revision: '1k3alNZCrLuNSi2fYJs9XP4eMSpSpy5r1',
};

const items = [];

for (const item of $input.all()) {
  const data = item.json;

  // ─── Parsear fecha ───
  const fechaStr = data.fecha_emision || new Date().toISOString().split('T')[0];
  const fecha = new Date(fechaStr);
  const año = fecha.getFullYear();
  const mes = String(fecha.getMonth() + 1).padStart(2, '0');
  const nombresMes = ['Enero','Febrero','Marzo','Abril','Mayo','Junio',
                      'Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
  const carpetaMes = `${mes}-${nombresMes[fecha.getMonth()]}`;

  // ─── Limpiar nombre del emisor ───
  const emisorLimpio = (data.emisor_nombre || 'SinEmisor')
    .replace(/[^a-zA-Z0-9áéíóúÁÉÍÓÚñÑ ]/g, '')
    .replace(/\s+/g, '-')
    .substring(0, 30);

  // ─── Construir nombre del archivo ───
  const numFactura = (data.numero_factura || 'SN').replace(/[^a-zA-Z0-9-]/g, '');
  const total = data.total ? `${data.total}€` : '';
  const nombreArchivo = `${fechaStr}_${emisorLimpio}_${numFactura}_${total}.pdf`;

  // ─── Ruta destino (informativa, para Sheets/logs) ───
  const carpetaTipo = data.tipo === 'proveedor' ? 'Proveedores' 
                    : data.tipo === 'cliente' ? 'Clientes'
                    : data.tipo === 'rectificativa' ? 'Rectificativas'
                    : 'Revision';
  const rutaDestino = `Facturas/${carpetaTipo}/${año}/${carpetaMes}`;

  // ─── CALCULAR FOLDER ID (lo que usa Drive) ───
  let folderId;
  if (data.revision_manual === true) {
    folderId = CARPETAS.revision;
  } else if (data.tipo === 'proveedor') {
    folderId = CARPETAS.proveedor;
  } else if (data.tipo === 'cliente') {
    folderId = CARPETAS.cliente;
  } else if (data.tipo === 'rectificativa') {
    folderId = CARPETAS.rectificativa;
  } else {
    folderId = CARPETAS.revision; // fallback: todo lo raro a revisión
  }

  items.push({
    json: {
      ...data,
      nombre_archivo: nombreArchivo,
      ruta_destino: rutaDestino,
      año: año,
      mes: carpetaMes,
      folder_id: folderId,        // ← esto es lo que usa el nodo Drive
    },
    binary: item.binary
  });
}

return items;

